// Haptic feedback manager using the Vibration API
// Mobile-only, gracefully degrades on unsupported devices

type HapticPattern = number | number[]

class HapticManager {
	private enabled = true
	private supported = false

	init(): void {
		this.supported = typeof navigator !== 'undefined' && 'vibrate' in navigator
	}

	private vibrate(pattern: HapticPattern): void {
		if (!this.enabled || !this.supported) return
		try {
			navigator.vibrate(pattern)
		} catch {
			// Silently fail - haptics are enhancement only
		}
	}

	// Game events - varying intensity/patterns
	perfectHit(): void {
		this.vibrate(35) // Strong short pulse
	}

	goodHit(): void {
		this.vibrate(20) // Medium pulse
	}

	miss(): void {
		this.vibrate([15, 30, 15]) // Double tap for negative feedback
	}

	comboMilestone(): void {
		this.vibrate([20, 20, 30]) // Celebratory pattern
	}

	levelUp(): void {
		this.vibrate([30, 40, 50, 40, 70]) // Escalating success pattern
	}

	// Generic feedback for UI interactions
	buttonTap(): void {
		this.vibrate(10) // Light tap
	}

	// Control methods
	setEnabled(enabled: boolean): void {
		this.enabled = enabled
	}

	isSupported(): boolean {
		return this.supported
	}
}

export const hapticManager = new HapticManager()
