import React from 'react';

interface HelpModalProps {
  isOpen: boolean;
  onClose: () => void;
  translations: {
    title: string;
    navigation: string;
    sections: string;
    themes: string;
    contact: string;
    easterEggs: string;
    ok: string;
  };
}

const HelpModal: React.FC<HelpModalProps> = ({ isOpen, onClose, translations }) => {
  if (!isOpen) return null;

  return (
    <div className="name-modal-overlay" onClick={onClose}>
      <div className="help-modal" onClick={(e) => e.stopPropagation()}>
        <div className="name-modal-titlebar">
          <span>{translations.title}</span>
          <button className="name-modal-close" onClick={onClose}>
            ×
          </button>
        </div>
        <div className="help-modal-content">
          <p>{translations.navigation}</p>
          <p>{translations.sections}</p>
          <p>{translations.themes}</p>
          <p>{translations.contact}</p>
          <p>{translations.easterEggs}</p>
          <div className="name-modal-buttons">
            <button type="button" onClick={onClose}>
              {translations.ok}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HelpModal;
